<style>
.rm-page{max-width:1280px;margin:0 auto}.rm-hero{display:flex;justify-content:space-between;align-items:flex-start;gap:16px;margin-bottom:18px}.rm-hero h1{font-size:30px;margin:0;color:#0f172a}.rm-hero p{margin:6px 0 0;color:#64748b}.rm-actions{display:flex;gap:10px;flex-wrap:wrap}.rm-btn{display:inline-flex;align-items:center;justify-content:center;border:0;border-radius:12px;background:#0f172a;color:#fff;padding:10px 14px;font-weight:800;text-decoration:none;cursor:pointer}.rm-btn.secondary{background:#eef2ff;color:#1d4ed8}.rm-grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px;margin-bottom:18px}.rm-stat{background:#fff;border:1px solid #e5e7eb;border-radius:18px;padding:16px}.rm-stat span{display:block;color:#64748b;font-size:12px;text-transform:uppercase;font-weight:800}.rm-stat strong{display:block;font-size:26px;color:#0f172a}.rm-card{background:#fff;border:1px solid #e5e7eb;border-radius:20px;overflow:hidden;margin-bottom:18px}.rm-card-header{padding:16px;border-bottom:1px solid #edf2f7;display:flex;justify-content:space-between;gap:10px;align-items:center}.rm-card-header h2{margin:0;font-size:18px}.rm-form{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:10px;padding:16px;border-bottom:1px solid #edf2f7}.rm-form input,.rm-form select,.rm-form textarea{border:1px solid #d8dee9;border-radius:12px;padding:10px 12px;width:100%}.rm-form textarea{grid-column:span 2}.rm-table{width:100%;border-collapse:collapse}.rm-table th{background:#f8fafc;color:#64748b;font-size:12px;text-transform:uppercase;text-align:left;padding:13px}.rm-table td{border-top:1px solid #edf2f7;padding:13px;vertical-align:top}.rm-badge{display:inline-flex;border-radius:999px;padding:4px 9px;font-size:12px;font-weight:800;background:#f1f5f9;color:#475569}.rm-badge.active,.rm-badge.paid,.rm-badge.occupied{background:#dcfce7;color:#166534}.rm-badge.vacant{background:#e0f2fe;color:#075985}.rm-badge.unpaid,.rm-badge.pending{background:#fee2e2;color:#991b1b}.rm-badge.partial,.rm-badge.reserved{background:#fef3c7;color:#92400e}.rm-muted{color:#64748b;font-size:13px}.rm-empty{padding:34px;text-align:center;color:#64748b}.rm-pagination{padding:14px;border-top:1px solid #edf2f7}.rm-alert{background:#dcfce7;color:#166534;border:1px solid #bbf7d0;border-radius:12px;padding:10px 14px;margin-bottom:14px;font-weight:700}@media(max-width:1000px){.rm-grid{grid-template-columns:repeat(2,1fr)}.rm-form{grid-template-columns:1fr}.rm-form textarea{grid-column:auto}.rm-table{display:block;overflow:auto}.rm-hero{display:block}}
</style>
